// swift-tools-version:6.0
import PackageDescription

// palbackend-ios — the managed-backend SDK (binary distribution).
//
// `import Palbe` gives a single entry point `pb`: generated typed endpoint
// calls (`pb.rooms.create(...)`), the untyped escape hatch (`pb.call`/
// `pb.upload`), and auth (`pb.auth.*`). The SDK ships as a closed-source
// XCFramework — `Palbe` is a binaryTarget, so consumers see only the public
// API (Cmd+Click shows no implementation). Source lives in a private repo.
//
// Typed calls are generated by the `palbase` CLI (`palbase backend types
// --lang swift`) from an Xcode Run Script build phase — see README. There is
// no SwiftPM codegen plugin: one path, the CLI.
let package = Package(
    name: "Palbe",
    platforms: [
        .iOS(.v15),
        .macOS(.v13),
        .tvOS(.v15),
        .watchOS(.v8)
    ],
    products: [
        .library(name: "Palbe", targets: ["Palbe"]),
        // Firebase-style: this one package URL also vends the codegen plugin.
        .plugin(name: "PalbaseCodegen", targets: ["PalbaseCodegenPlugin"]),
        .executable(name: "palbase-swiftgen", targets: ["palbase-swiftgen"]),
    ],
    targets: [
        .binaryTarget(
            name: "Palbe",
            url: "https://github.com/palgroup/palbackend-ios/releases/download/v0.24.1/Palbe.xcframework.zip",
            checksum: "32aae5e76f31cf042c75c79958d9dbde732b504e21400b51f1adc7bb4d388aad"
        ),
        .executableTarget(name: "palbase-swiftgen", path: "Sources/palbase-swiftgen"),
        .plugin(
            name: "PalbaseCodegenPlugin",
            capability: .buildTool(),
            dependencies: ["palbase-swiftgen"],
            path: "Plugins/PalbaseCodegenPlugin"
        ),
    ],
    swiftLanguageModes: [.v6]
)
